class TestTruncatePath:
    def test_short_path_unchanged(self):
        path = "/home/user/project"
        assert voice._truncate_path(path) == path

    def test_exact_max_length_unchanged(self):
        path = "x" * voice.MAX_PATH_DISPLAY_LENGTH
        assert voice._truncate_path(path) == path

    def test_long_path_truncated(self):
        path = "x" * 100
        result = voice._truncate_path(path)
        assert result.startswith("...")
        assert len(result) == voice.MAX_PATH_DISPLAY_LENGTH

    def test_custom_max_length(self):
        path = "/a/very/long/path/that/exceeds/twenty/chars"
        result = voice._truncate_path(path, max_length=20)
        assert len(result) == 20
        assert result.startswith("...")


