def _mock_tk(*, num_devices=0):
    """Return a set of patches that mock all tkinter widgets used by record_with_gui."""
    mock_root = MagicMock()
    mock_root.mainloop.return_value = None

    patches = {
        "tk": patch("voice.tk.Tk", return_value=mock_root),
        "stringvar": patch("voice.tk.StringVar", return_value=MagicMock()),
        "label": patch("voice.tk.Label", return_value=MagicMock()),
        "frame": patch("voice.tk.Frame", return_value=MagicMock()),
        "button": patch("voice.tk.Button", return_value=MagicMock()),
        "root": mock_root,
    }
    if num_devices > 1:
        patches["combobox"] = patch(
            "voice.ttk.Combobox", return_value=MagicMock()
        )
    return patches


def _apply_tk_patches(tk_mocks):
    """Yield context managers for all patches in tk_mocks dict (skip 'root')."""
    return [v for k, v in tk_mocks.items() if k != "root"]


